from typing import Dict, List, Optional, Any
from enum import Enum
from dataclasses import dataclass
from decimal import Decimal

class UserTier(Enum):
    BASIC = "basic"
    PREMIUM = "premium"
    VIP = "vip"
    ADMIN = "admin"

class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"

@dataclass
class CartItem:
    product_id: str
    name: str
    price: Decimal
    quantity: int
    taxable: bool = True

@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountType
    value: Decimal
    allowed_tiers: List[UserTier]
    min_purchase: Decimal = Decimal('0')
    max_discount: Optional[Decimal] = None

@dataclass
class User:
    user_id: str
    tier: UserTier
    email: str

@dataclass
class PaymentInfo:
    method: str
    card_number: Optional[str] = None
    token: Optional[str] = None

class CheckoutError(Exception):
    pass

class ValidationError(CheckoutError):
    pass

class DiscountError(CheckoutError):
    pass

class TaxError(CheckoutError):
    pass

class PaymentError(CheckoutError):
    pass

class OrderError(CheckoutError):
    pass

def validate_cart_items(cart_items: List[CartItem]) -> Dict[str, Any]:
    if not cart_items:
        raise ValidationError("Cart is empty")
    
    validated_items = []
    subtotal = Decimal('0')
    
    for item in cart_items:
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for item {item.product_id}")
        
        if item.price < 0:
            raise ValidationError(f"Invalid price for item {item.product_id}")
        
        if not item.product_id or not item.name:
            raise ValidationError(f"Missing product information for item")
        
        item_total = item.price * item.quantity
        subtotal += item_total
        
        validated_items.append({
            'product_id': item.product_id,
            'name': item.name,
            'price': item.price,
            'quantity': item.quantity,
            'taxable': item.taxable,
            'item_total': item_total
        })
    
    return {
        'items': validated_items,
        'subtotal': subtotal,
        'valid': True
    }

def apply_discount_codes(
    validation_result: Dict[str, Any],
    discount_codes: List[str],
    available_discounts: Dict[str, DiscountCode],
    user: User
) -> Dict[str, Any]:
    if not validation_result.get('valid'):
        raise DiscountError("Cannot apply discounts to invalid cart")
    
    subtotal = validation_result['subtotal']
    total_discount = Decimal('0')
    applied_discounts = []
    
    for code in discount_codes:
        if code not in available_discounts:
            raise DiscountError(f"Invalid discount code: {code}")
        
        discount = available_discounts[code]
        
        if user.tier not in discount.allowed_tiers:
            raise DiscountError(
                f"User tier '{user.tier.value}' not authorized to use discount code '{code}'. "
                f"Required tiers: {[t.value for t in discount.allowed_tiers]}"
            )
        
        if subtotal < discount.min_purchase:
            raise DiscountError(
                f"Minimum purchase of {discount.min_purchase} required for code '{code}'"
            )
        
        discount_amount = Decimal('0')
        if discount.discount_type == DiscountType.PERCENTAGE:
            discount_amount = subtotal * (discount.value / Decimal('100'))
        elif discount.discount_type == DiscountType.FIXED:
            discount_amount = discount.value
        
        if discount.max_discount and discount_amount > discount.max_discount:
            discount_amount = discount.max_discount
        
        total_discount += discount_amount
        applied_discounts.append({
            'code': code,
            'type': discount.discount_type.value,
            'amount': discount_amount
        })
    
    if total_discount > subtotal:
        total_discount = subtotal
    
    discounted_total = subtotal - total_discount
    
    return {
        **validation_result,
        'discount_amount': total_discount,
        'applied_discounts': applied_discounts,
        'discounted_total': discounted_total
    }

def calculate_tax(
    discount_result: Dict[str, Any],
    tax_rate: Decimal,
    tax_region: str
) -> Dict[str, Any]:
    if tax_rate < 0 or tax_rate > 1:
        raise TaxError("Invalid tax rate")
    
    taxable_amount = Decimal('0')
    
    for item in discount_result['items']:
        if item['taxable']:
            item_subtotal = item['price'] * item['quantity']
            discount_ratio = discount_result['discounted_total'] / discount_result['subtotal']
            discounted_item_total = item_subtotal * discount_ratio
            taxable_amount += discounted_item_total
    
    tax_amount = taxable_amount * tax_rate
    total_with_tax = discount_result['discounted_total'] + tax_amount
    
    return {
        **discount_result,
        'tax_rate': tax_rate,
        'tax_region': tax_region,
        'taxable_amount': taxable_amount,
        'tax_amount': tax_amount,
        'total': total_with_tax
    }

def process_payment(
    tax_result: Dict[str, Any],
    payment_info: PaymentInfo,
    user: User
) -> Dict[str, Any]:
    total = tax_result['total']
    
    if total <= 0:
        raise PaymentError("Invalid payment amount")
    
    if not payment_info.method:
        raise PaymentError("Payment method required")
    
    if payment_info.method == "credit_card":
        if not payment_info.card_number and not payment_info.token:
            raise PaymentError("Credit card information required")
    
    transaction_id = f"TXN-{user.user_id}-{hash(str(total))}"
    
    payment_result = {
        'transaction_id': transaction_id,
        'amount_charged': total,
        'payment_method': payment_info.method,
        'status': 'completed'
    }
    
    return {
        **tax_result,
        'payment': payment_result
    }

def create_order_record(
    payment_result: Dict[str, Any],
    user: User,
    shipping_address: Dict[str, str]
) -> Dict[str, Any]:
    if payment_result['payment']['status'] != 'completed':
        raise OrderError("Cannot create order for incomplete payment")
    
    if not shipping_address or not shipping_address.get('address'):
        raise OrderError("Shipping address required")
    
    order_id = f"ORD-{user.user_id}-{payment_result['payment']['transaction_id']}"
    
    order = {
        'order_id': order_id,
        'user_id': user.user_id,
        'user_email': user.email,
        'items': payment_result['items'],
        'subtotal': payment_result['subtotal'],
        'discount_amount': payment_result.get('discount_amount', Decimal('0')),
        'applied_discounts': payment_result.get('applied_discounts', []),
        'tax_amount': payment_result['tax_amount'],
        'total': payment_result['total'],
        'payment': payment_result['payment'],
        'shipping_address': shipping_address,
        'status': 'confirmed'
    }
    
    return order

def checkout(
    cart_items: List[CartItem],
    user: User,
    discount_codes: List[str],
    available_discounts: Dict[str, DiscountCode],
    tax_rate: Decimal,
    tax_region: str,
    payment_info: PaymentInfo,
    shipping_address: Dict[str, str]
) -> Dict[str, Any]:
    step1 = validate_cart_items(cart_items)
    
    step2 = apply_discount_codes(step1, discount_codes, available_discounts, user)
    
    step3 = calculate_tax(step2, tax_rate, tax_region)
    
    step4 = process_payment(step3, payment_info, user)
    
    step5 = create_order_record(step4, user, shipping_address)
    
    return step5